// ── OneSignal push notification helper ───────────────────────────────────────
async function sendPush({ playerIds, title, message }) {
  if (!playerIds || playerIds.length === 0) return;
  try {
    await fetch("/.netlify/functions/notify", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ playerIds, title, message }),
    });
  } catch (e) {
    console.warn("Push notification failed:", e);
  }
}

// ── OneSignal SDK loader ──────────────────────────────────────────────────────
function useOneSignal() {
  const [playerId, setPlayerId] = useState(() => load("tfs_player_id", null));
  const [notifStatus, setNotifStatus] = useState(() => {
    if (typeof Notification !== "undefined") return Notification.permission;
    return "unknown";
  });

  useEffect(() => {
    if (typeof window === "undefined") return;
    window.OneSignalDeferred = window.OneSignalDeferred || [];
    const script = document.createElement("script");
    script.src = "https://cdn.onesignal.com/sdks/web/v16/OneSignalSDK.page.js";
    script.async = true;
    script.onload = () => {
      window.OneSignalDeferred.push(async (OS) => {
        try {
          await OS.init({
            appId: ONESIGNAL_APP_ID,
            serviceWorkerParam: { scope: "/" },
            notifyButton: { enable: false },
            allowLocalhostAsSecureOrigin: true,
          });
          const granted = await OS.Notifications.permission;
          if (granted) {
            setNotifStatus("granted");
            const id = OS.User.PushSubscription.id;
            if (id) { setPlayerId(id); save("tfs_player_id", id); }
          }
          OS.User.PushSubscription.addEventListener("change", e => {
            if (e.current?.id) {
              setPlayerId(e.current.id);
              save("tfs_player_id", e.current.id);
              setNotifStatus("granted");
            }
          });
        } catch(e) { console.warn("OneSignal init failed:", e); }
      });
    };
    document.head.appendChild(script);
    return () => { try { document.head.removeChild(script); } catch(e){} };
  }, []);

  const requestPermission = async () => {
    try {
      if (window.OneSignal) {
        await window.OneSignal.Notifications.requestPermission();
        await new Promise(r => setTimeout(r, 1000));
        const id = window.OneSignal.User.PushSubscription.id;
        if (id) {
          setPlayerId(id);
          save("tfs_player_id", id);
          setNotifStatus("granted");
          return;
        }
      }
      // Fallback to native
      if ("Notification" in window) {
        const perm = await Notification.requestPermission();
        setNotifStatus(perm);
      }
    } catch(e) {
      console.warn("Permission request failed:", e);
    }
  };

  return { playerId, notifStatus, requestPermission };
}

// ── Pie Chart ────────────────────────────────────────────────────────────────
function PieChart({slices}){
  const[hov,setHov]=useState(null);
  const size=160,cx=80,cy=80,r=64,ir=32;
  const total=slices.reduce((s,x)=>s+x.value,0);
  if(!total)return <div style={{textAlign:"center",padding:"20px 0",color:"#bbb",fontSize:13}}>No tasks yet</div>;
  let angle=-Math.PI/2;
  const paths=slices.map((sl,i)=>{
    const pct=sl.value/total,sweep=pct*2*Math.PI;
    const x1=cx+r*Math.cos(angle),y1=cy+r*Math.sin(angle);
    angle+=sweep;
    const x2=cx+r*Math.cos(angle),y2=cy+r*Math.sin(angle);
    const xi1=cx+ir*Math.cos(angle-sweep),yi1=cy+ir*Math.sin(angle-sweep);
    const xi2=cx+ir*Math.cos(angle),yi2=cy+ir*Math.sin(angle);
    const lg=sweep>Math.PI?1:0;
    return{d:`M${xi1} ${yi1}L${x1} ${y1}A${r} ${r} 0 ${lg} 1 ${x2} ${y2}L${xi2} ${yi2}A${ir} ${ir} 0 ${lg} 0 ${xi1} ${yi1}Z`,...sl,pct:Math.round(pct*100),i};
  });
  const h=hov!=null?paths[hov]:null;
  return(
    <div style={{display:"flex",alignItems:"center",gap:16}}>
      <svg width={size} height={size} style={{flexShrink:0,filter:"drop-shadow(0 3px 8px rgba(0,0,0,0.1))"}}>
        {paths.map((p,i)=><path key={i} d={p.d} fill={p.color} stroke="rgba(255,255,255,0.6)" strokeWidth={hov===i?2:1.5}
          opacity={hov!=null&&hov!==i?0.5:1} style={{cursor:"pointer",transition:"opacity .2s"}}
          onMouseEnter={()=>setHov(i)} onMouseLeave={()=>setHov(null)}/>)}
        <text x={cx} y={cy-6} textAnchor="middle" fontSize="16" fontWeight="700" fontFamily="Bebas Neue,sans-serif" fill="#1a1a1a">{h?h.pct+"%":total}</text>
        <text x={cx} y={cy+8} textAnchor="middle" fontSize="9" fontFamily="DM Sans,sans-serif" fill="#aaa" letterSpacing="1">{h?h.label.toUpperCase().slice(0,10):"TOTAL TASKS"}</text>
      </svg>
      <div style={{flex:1,display:"flex",flexDirection:"column",gap:5}}>
        {paths.map((p,i)=>(
          <div key={i} style={{display:"flex",alignItems:"center",gap:7,cursor:"pointer",opacity:hov!=null&&hov!==i?0.4:1,transition:"opacity .2s"}}
            onMouseEnter={()=>setHov(i)} onMouseLeave={()=>setHov(null)}>
            <div style={{width:9,height:9,borderRadius:2,background:p.color,flexShrink:0}}/>
            <span style={{fontSize:11,color:"#555",flex:1,fontWeight:hov===i?700:400}}>{p.label}</span>
            <span style={{fontSize:11,fontWeight:700,color:"#1a1a1a"}}>{p.pct}%</span>
          </div>
        ))}
      </div>
    </div>
  );
}

